import type { TrainingExecution, TrainingPlan, WeekDay } from '../types/database'

const WEEKDAY_MAP: Record<WeekDay, number> = {
  sun: 0,
  mon: 1,
  tue: 2,
  wed: 3,
  thu: 4,
  fri: 5,
  sat: 6,
}

export function calculateTotalSessions(plan: TrainingPlan): number {
  return Math.ceil(plan.total_amount / plan.unit_amount)
}

export function calculateEndDate(plan: TrainingPlan, executions?: TrainingExecution[]): Date {
  const hasExecutions = executions && executions.length > 0

  let fromDate: Date
  let sessions: number

  if (hasExecutions) {
    const completedUnits = executions.reduce((sum, e) => sum + e.unit_count, 0)
    const remainingAmount = Math.max(0, plan.total_amount - completedUnits)
    sessions = Math.ceil(remainingAmount / plan.unit_amount)
    fromDate = new Date()
  } else {
    sessions = calculateTotalSessions(plan)
    fromDate = new Date(plan.start_date)
  }

  if (sessions <= 0) return fromDate

  if (plan.schedule_type === 'daily') {
    const endDate = new Date(fromDate)
    endDate.setDate(endDate.getDate() + sessions - 1)
    return endDate
  }

  // weekly schedule
  const scheduleDays = plan.schedule_days ?? []
  if (scheduleDays.length === 0) {
    return fromDate
  }

  const dayNumbers = scheduleDays.map((d) => WEEKDAY_MAP[d]).sort((a, b) => a - b)
  const currentDate = new Date(fromDate)
  let sessionsScheduled = 0

  while (sessionsScheduled < sessions) {
    const currentDay = currentDate.getDay()
    if (dayNumbers.includes(currentDay)) {
      sessionsScheduled++
      if (sessionsScheduled >= sessions) {
        break
      }
    }
    currentDate.setDate(currentDate.getDate() + 1)
  }

  return currentDate
}

export function formatDate(date: Date): string {
  return date.toLocaleDateString('ko-KR', {
    year: 'numeric',
    month: 'long',
    day: 'numeric',
  })
}

export function getWeekDayLabel(day: WeekDay): string {
  const labels: Record<WeekDay, string> = {
    mon: '월',
    tue: '화',
    wed: '수',
    thu: '목',
    fri: '금',
    sat: '토',
    sun: '일',
  }
  return labels[day]
}

export const ALL_WEEKDAYS: WeekDay[] = ['mon', 'tue', 'wed', 'thu', 'fri', 'sat', 'sun']

const NUMBER_TO_WEEKDAY: WeekDay[] = ['sun', 'mon', 'tue', 'wed', 'thu', 'fri', 'sat']

export function isScheduledForDate(plan: TrainingPlan, date: Date): boolean {
  const startDate = new Date(plan.start_date)
  startDate.setHours(0, 0, 0, 0)

  const checkDate = new Date(date)
  checkDate.setHours(0, 0, 0, 0)

  // Check if date is before start date
  if (checkDate < startDate) {
    return false
  }

  // Check if date is after end date
  const endDate = calculateEndDate(plan)
  endDate.setHours(23, 59, 59, 999)
  if (checkDate > endDate) {
    return false
  }

  if (plan.schedule_type === 'daily') {
    return true
  }

  // weekly schedule - check if the day matches
  const scheduleDays = plan.schedule_days ?? []
  const dayOfWeek = NUMBER_TO_WEEKDAY[checkDate.getDay()]
  return scheduleDays.includes(dayOfWeek)
}

export function getTodaysPlans(plans: TrainingPlan[]): TrainingPlan[] {
  const today = new Date()
  return plans.filter((plan) => !plan.completed_at && isScheduledForDate(plan, today))
}
